require "config.Define"
require "packet.GamePacketSender"
require "util.ReportUtil"

VideoAdHelper = {}
VideoAdHelper.defaultIntervalTime = 1800

function VideoAdHelper:setIntervalTime(config)
    self.defaultIntervalTime = tonumber(config) or 1800
end

function VideoAdHelper:initPlayerData(player)
    local curTime = os.time()
    --print(" VideoAdHelper:initPlayerData"..self.defaultIntervalTime)
    --print(player.lookAdTime)
    if player.lookAdTime == nil or curTime - player.lookAdTime >= self.defaultIntervalTime then
        --print(" VideoAdHelper:initPlayerData open")
        self:sendOpenAd(player)
    else
        --print("VideoAdHelper:initPlayerData close")
        self:sendCloseAd(player)
        local tick = (player.lookAdTime + self.defaultIntervalTime) - curTime
        LuaTimer:schedule(function(player)
            VideoAdHelper:sendOpenAd(player)
        end, tick * 1000, nil, player)
    end
end

function VideoAdHelper:sendCloseAd(player)
    local params = {
        itemId = Define.ItemIdAd.ItemID,
        adType = Define.AdType.AppShop,
        isShow = false,
        position = 0,
    }
    local data = DataBuilder.new():fromTable(params):getData()
    --print("close Ad")
    GamePacketSender:sendAppShopVideoData(player.rakssid, data)
end

function VideoAdHelper:sendOpenAd(player)
    local params = {
        itemId = Define.ItemIdAd.ItemID,
        adType = Define.AdType.AppShop,
        isShow = true,
        position = 0,
    }
    local data = DataBuilder.new():fromTable(params):getData()
    --print("open Ad")
    GamePacketSender:sendAppShopVideoData(player.rakssid, data)
end

function VideoAdHelper:onShopVideoAdReward(player)
    --print("VideoAdHelper:onShopVideoAdReward")
    VideoAdHelper:sendCloseAd(player)
    player:addCurrency(100)
    player.lookAdTime = os.time()
    LuaTimer:schedule(function(player)
        VideoAdHelper:sendOpenAd(player)
    end, VideoAdHelper.defaultIntervalTime * 1000, nil, player)
end

function VideoAdHelper:onLotteryVideoAdReward(player, id)
    --print("VideoAdHelper:onLotteryVideoAdReward 1 "..id)
    local actor = ActorsConfig:getActorById(id)
    if actor == nil or player.actors == nil then
        --print("VideoAdHelper:onLotteryVideoAdReward not "..id)
        return
    end
    --print("VideoAdHelper:onLotteryVideoAdReward 2 "..id)
    if player.actors[id] == nil then
        --print("VideoAdHelper:onLotteryVideoAdReward add "..id)
        player.actors[id] = GamePlayer.HAVE_ACTOR_STATE
        HostApi.notifyGetGoods(player.rakssid, actor.image, 1)
        --ReportUtil:reportLookedAdGetActor(player, id)
        player:sendActorsData()
        --print(json.encode(player.actors))
    end

end

return VideoAdHelper